Dependencyratio', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04519', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關第八版國人膳食營養素參考攝取量（DRIs）中「鈣質」的敘述，下列何者正確？', '["13～18歲為成長階段，鈣質建議值為1,200毫克", "50歲後為鈣質快速流失階段，為預防骨質疏鬆，鈣質建議值為1,200毫克", "累積骨本應從小開始，1～3歲鈣質建議值為1,200毫克", "30歲達到骨質巔峰，故30歲後宜提高鈣質攝取預防骨質疏鬆，其建議值為1,200毫克"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04520', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關第八版國人膳食營養素參考攝取量（DRIs）之敘述，下列何者正確？', '["膳食纖維的建議量與上限攝取量，係依每日熱量的建議攝取量訂定", "在日照及飲食鈣充足情況下，0～50歲國人維生素D的建議量為每日攝取10μg", "孕期碘的需求為母親與胎兒需要量之總和，建議自懷孕第一期即增加碘之攝取量", "礦物質中的鐵、硒、鉀，在DRIs中採用的建議量是足夠攝取量（AdequateIntakes,AI）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04521', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列有關膳食營養素參考攝取量（DRIs）中之巨量營養素可接受範圍（AMDR）敘述，何者錯誤？', '["AMDR有利於慢性疾病預防與發生率的降低", "AMDR須符合熱量營養素與微量營養素的需求", "AMDR指在飲食中碳水化合物、脂質及蛋白質等應有適宜的熱量攝取分配範圍", "全年齡層，對於總碳水化合物攝取量，納入AMDR的概念，制定適宜攝取之範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "5d38408647b2", "answer_pdf_sha1": "f94dd9c2be8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
